.map-container .box me-parent me-tpc .before {
  height: 14px;
  top: -14px;
}
.map-container .box me-parent me-tpc .in {
  height: 100%;
  top: 0px;
}
.map-container .box me-parent me-tpc .after {
  height: 14px;
  bottom: -14px;
}
