  top: 0;
  left: 0;
  background-color: #fff;
  color: #666666;
  width: max-content;
  max-width: 800px;
  z-index: 11;
  direction: ltr;
  user-select: auto;
}
me-tpc > img {
  pointer-events: none;
  display: block;
}
.circle {
  position: absolute;
  height: 10px;
  width: 10px;
  margin-top: -5px;
  margin-left: -5px;
  border-radius: 100%;
  background: #aaa;
  cursor: pointer;
}
